from anthropic import Anthropic

client = Anthropic()

def ask_with_extended_thinking(question: str, budget_tokens: int = 5000) -> dict:
    """
    Returns {"answer": str, "thinking": str} using Anthropic's native
    extended thinking. Requires claude-3-7-sonnet-20250219 or later.
    """
    response = client.messages.create(
        model="claude-3-7-sonnet-20250219",
        max_tokens=8000,
        thinking={
            "type": "enabled",
            "budget_tokens": budget_tokens,
        },
        messages=[{"role": "user", "content": question}],
    )

    thinking_text = ""
    answer_text = ""
    for block in response.content:
        if block.type == "thinking":
            thinking_text = block.thinking
        elif block.type == "text":
            answer_text = block.text

    return {"answer": answer_text, "thinking": thinking_text}

result = ask_with_extended_thinking(
    "A biased coin lands heads 60% of the time. What is the probability "
    "of getting at least 4 heads in 6 flips?"
)
print("Answer:", result["answer"])
print("Thinking tokens used:", len(result["thinking"].split()))

from langchain_anthropic import ChatAnthropic
from langchain_core.messages import HumanMessage

llm = ChatAnthropic(
    model="claude-3-7-sonnet-20250219",
    max_tokens=8000,
    thinking={"type": "enabled", "budget_tokens": 5000},
)

response = llm.invoke([HumanMessage(content="Solve: if 3x + 7 = 22, what is x?")])
for block in response.content:
    if block.get("type") == "thinking":
        print("THINKING:", block["thinking"][:100], "...")
    elif block.get("type") == "text":
        print("ANSWER:", block["text"])
